  9→  snapRectToGrid,
 10→} from './standards';
 11→import { getPaperPreset } from './paper';
 12→import { getViewportSourceLabel, resolveSheetViewportSource } from './sources';
 13→
 14→function clamp(value, min, max) {
 15→  return Math.max(min, Math.min(max, value));
 16→}
 17→
 18→function sourceFitsFrame(source) {
 19→  return source?.kind === '3d_preview' || source?.kind === 'roof_schedule';
 20→}
 21→
 22→function resolveViewportScale(viewport) {
 23→  return Math.max(1, Number(viewport?.scale) || 100);
 24→}
