 26→function getCaptionClearance(viewport) {
 27→  if (viewport?.captionPosition === 'above' || viewport?.captionPosition === 'below') {
 28→    return SHEET_TOKENS.viewportCaptionGap + SHEET_TOKENS.viewportCaptionHeight;
 29→  }
 30→  return 0;
 31→}
