149→function buildTitleBlock(project, sheet, titleBlockRect, index, viewports) {
150→  const meta = resolveSheetMetadata(project, sheet, index, viewports);
151→  const revisionWidth = Math.max(44, titleBlockRect.width * 0.28);
152→  const infoX = titleBlockRect.x + titleBlockRect.width - revisionWidth;
153→  const mainWidth = titleBlockRect.width - revisionWidth;
154→  const bandHeight = titleBlockRect.height * 0.3;
155→  const titleHeight = titleBlockRect.height * 0.36;
156→  const metaRowHeight = (titleBlockRect.height - bandHeight - titleHeight) / 2;
157→  const metaLabelWidth = 15;
158→  const visibleRevisions = [...(sheet?.revisions || [])].slice(-4).reverse();
159→
160→  return {
161→    frame: titleBlockRect,
162→    projectBand: {
163→      x: titleBlockRect.x,
164→      y: titleBlockRect.y,
165→      width: mainWidth,
166→      height: bandHeight,
167→      title: meta.projectTitle,
168→      address: meta.projectAddress,
169→    },
170→    drawingCell: {
171→      x: titleBlockRect.x,
172→      y: titleBlockRect.y + bandHeight,
173→      width: mainWidth * 0.68,
174→      height: titleHeight,
175→      label: 'DRAWING TITLE',
176→      value: meta.drawingTitle,
177→    },
178→    numberCell: {
179→      x: titleBlockRect.x + mainWidth * 0.68,
180→      y: titleBlockRect.y + bandHeight,
181→      width: mainWidth * 0.32,
182→      height: titleHeight,
183→      label: 'SHEET NO.',
184→      value: meta.sheetNumber,
185→    },
186→    metaRows: [
187→      {
188→        x: titleBlockRect.x,
189→        y: titleBlockRect.y + bandHeight + titleHeight,
190→        width: mainWidth / 2,
191→        height: metaRowHeight,
192→        labelWidth: metaLabelWidth,
193→        label: 'DATE',
194→        value: meta.issueDate,
195→      },
196→      {
197→        x: titleBlockRect.x + mainWidth / 2,
198→        y: titleBlockRect.y + bandHeight + titleHeight,
199→        width: mainWidth / 2,
200→        height: metaRowHeight,
201→        labelWidth: metaLabelWidth,
202→        label: 'SCALE',
203→        value: meta.scaleLabel,
204→      },
205→      {
206→        x: titleBlockRect.x,
207→        y: titleBlockRect.y + bandHeight + titleHeight + metaRowHeight,
208→        width: mainWidth / 2,
209→        height: metaRowHeight,
210→        labelWidth: metaLabelWidth,
211→        label: 'DRAWN BY',
212→        value: meta.drawnBy || 'TBD',
213→      },
214→      {
215→        x: titleBlockRect.x + mainWidth / 2,
216→        y: titleBlockRect.y + bandHeight + titleHeight + metaRowHeight,
217→        width: mainWidth / 2,
218→        height: metaRowHeight,
219→        labelWidth: metaLabelWidth,
220→        label: 'CHECKED',
221→        value: meta.checkedBy || 'TBD',
222→      },
223→    ],
224→    revisions: {
225→      x: infoX,
226→      y: titleBlockRect.y,
227→      width: revisionWidth,
228→      height: titleBlockRect.height,
229→      headerHeight: 8,
230→      rows: visibleRevisions,
231→    },
232→  };
233→}
234→
235→function rectFromArea(area) {
236→  return {
237→    x: area.x,
238→    y: area.y,
239→    width: area.width,
240→    height: area.height,
241→  };
242→}
243→
244→function partitionByRole(entries) {
245→  const primary = [];
246→  const secondary = [];
247→  const supplemental = [];
248→
249→  entries.forEach((entry, index) => {
250→    const role = entry.viewport.role
251→      || (entry.source.kind === '3d_preview' ? 'supplemental' : (index === 0 ? 'primary' : 'secondary'));
252→
253→    if (role === 'supplemental' || entry.source.kind === '3d_preview') {
254→      supplemental.push(entry);
255→    } else if (role === 'primary') {
256→      primary.push(entry);
257→    } else {
258→      secondary.push(entry);
259→    }
260→  });
261→
262→  return { primary, secondary, supplemental };
263→}
264→
265→function stackAreas(area, count) {
266→  if (count <= 0) return [];
267→  if (count === 1) return [rectFromArea(area)];
268→  if (count >= 4) {
269→    const columns = 2;
270→    const rows = Math.ceil(count / columns);
271→    const cellWidth = (area.width - SHEET_TOKENS.viewportGutter) / columns;
272→    const cellHeight = (area.height - SHEET_TOKENS.viewportGutter * (rows - 1)) / rows;
273→    return Array.from({ length: count }, (_, index) => {
274→      const column = index % columns;
275→      const row = Math.floor(index / columns);
276→      return {
277→        x: area.x + column * (cellWidth + SHEET_TOKENS.viewportGutter),
278→        y: area.y + row * (cellHeight + SHEET_TOKENS.viewportGutter),
279→        width: cellWidth,
280→        height: cellHeight,
281→      };
282→    });
283→  }
284→
285→  const height = (area.height - SHEET_TOKENS.viewportGutter * (count - 1)) / count;
286→  return Array.from({ length: count }, (_, index) => ({
287→    x: area.x,
288→    y: area.y + index * (height + SHEET_TOKENS.viewportGutter),
289→    width: area.width,
290→    height,
291→  }));
292→}
293→
294→function layoutAutoViewports(entries, area) {
295→  if (!entries.length) return new Map();
296→
297→  const result = new Map();
298→  const roles = partitionByRole(entries);
299→  const primaryEntry = roles.primary[0] || roles.secondary[0] || roles.supplemental[0];
300→  const secondaryEntries = [
301→    ...roles.primary.slice(primaryEntry && roles.primary[0] === primaryEntry ? 1 : 0),
302→    ...roles.secondary.filter((entry) => entry !== primaryEntry),
303→    ...roles.supplemental.filter((entry) => entry !== primaryEntry),
304→  ];
305→
306→  if (!primaryEntry) return result;
307→
308→  const onlySupplemental = primaryEntry.source.kind === '3d_preview'
309→    && secondaryEntries.every((entry) => entry.source.kind === '3d_preview');
310→
311→  if (!secondaryEntries.length) {
312→    result.set(primaryEntry.viewport.id, rectFromArea(area));
313→    return result;
314→  }
315→
316→  if (onlySupplemental) {
317→    const areas = stackAreas(area, 1 + secondaryEntries.length);
318→    [primaryEntry, ...secondaryEntries].forEach((entry, index) => {
319→      result.set(entry.viewport.id, areas[index]);
320→    });
321→    return result;
322→  }
323→
324→  const primaryWidthRatio = secondaryEntries.length >= 3 ? 0.58 : 0.64;
325→  const primaryArea = {
326→    x: area.x,
327→    y: area.y,
328→    width: area.width * primaryWidthRatio - SHEET_TOKENS.viewportGutter / 2,
329→    height: area.height,
330→  };
331→  const sideArea = {
332→    x: primaryArea.x + primaryArea.width + SHEET_TOKENS.viewportGutter,
333→    y: area.y,
334→    width: area.width - primaryArea.width - SHEET_TOKENS.viewportGutter,
335→    height: area.height,
336→  };
337→
338→  result.set(primaryEntry.viewport.id, rectFromArea(primaryArea));
339→  stackAreas(sideArea, secondaryEntries.length).forEach((rect, index) => {
340→    result.set(secondaryEntries[index].viewport.id, rect);
341→  });
342→
343→  return result;
344→}
345→
346→export function buildSheetScene(project, sheet) {
347→  if (!sheet) return null;
348→
349→  const paper = getPaperPreset(sheet.paperSize);
350→  const zones = buildSheetZones(paper);
351→  const sourceEntries = (sheet.viewports || []).map((viewport) => ({
352→    viewport,
353→    source: resolveSheetViewportSource(project, viewport, {
354→      activePhaseId: viewport.phaseId,
355→      phaseViewMode: viewport.phaseViewMode || 'all',
356→    }),
357→  }));
358→  const allowAutoLayout = sheet.layoutTemplate !== 'manual';
359→  const autoEntries = allowAutoLayout
360→    ? sourceEntries.filter((entry) => !entry.viewport.lockAutoLayout)
361→    : [];
362→  const manualEntries = sourceEntries.filter((entry) => entry.viewport.lockAutoLayout);
363→  const autoRects = layoutAutoViewports(autoEntries, zones.contentArea);
364→
365→  const sceneViewports = sourceEntries.map((entry) => {
366→    const rect = autoRects.get(entry.viewport.id)
367→      || fitViewportToSheet(entry.viewport, sheet);
368→    return buildViewportScene(entry.viewport, entry.source, sheet, rect);
369→  });
370→
371→  const sheetIndex = (project?.sheets || []).findIndex((entry) => entry.id === sheet.id);
372→
373→  return {
374→    paper,
375→    title: getSheetDisplayLabel(sheet, Math.max(0, sheetIndex)),
376→    border: zones.border,
377→    liveArea: zones.liveArea,
378→    contentArea: zones.contentArea,
379→    footer: zones.footer,
380→    titleBlock: buildTitleBlock(project, sheet, zones.titleBlock, Math.max(0, sheetIndex), sceneViewports),
381→    viewports: sceneViewports,
382→    graphics: {
383→      colors: SHEET_COLORS,
384→      drawing: DRAWING_GRAPHICS,
385→    },
386→    manualViewportCount: manualEntries.length,
387→  };
388→}
389→
390→export function materializeSheetViewportFrames(project, sheet) {
391→  if (!sheet) return sheet;
392→
393→  const scene = buildSheetScene(project, {
394→    ...sheet,
395→    layoutTemplate: 'auto',
396→  });
397→
398→  if (!scene) return sheet;
399→
400→  const frameById = new Map(scene.viewports.map((viewport) => [viewport.id, viewport]));
401→
402→  return {
403→    ...sheet,
404→    layoutTemplate: 'manual',
405→    viewports: (sheet.viewports || []).map((viewport) => {
406→      const frame = frameById.get(viewport.id);
407→      if (!frame) {
408→        return {
409→          ...viewport,
410→          lockAutoLayout: true,
411→        };
412→      }
413→
414→      return {
415→        ...viewport,
416→        x: frame.x,
417→        y: frame.y,
418→        width: frame.width,
419→        height: frame.height,
420→        rotation: frame.rotation || 0,
421→        lockAutoLayout: true,
422→      };
423→    }),
424→  };
425→}
426→
427→export function fitViewportToSheet(viewport, sheet) {
428→  const paper = getPaperPreset(sheet.paperSize);
429→  const zones = buildSheetZones(paper);
430→  const captionClearance = getCaptionClearance(viewport);
431→  const captionAbove = viewport.captionPosition === 'above' ? captionClearance : 0;
432→  const captionBelow = viewport.captionPosition === 'below' ? captionClearance : 0;
433→  const width = clamp(
434→    viewport.width,
435→    SHEET_TOKENS.viewportMinWidth,
436→    zones.contentArea.width
437→  );
438→  const height = clamp(
439→    viewport.height,
440→    SHEET_TOKENS.viewportMinHeight,
441→    zones.contentArea.height - captionClearance
442→  );
443→  const maxX = zones.contentArea.x + zones.contentArea.width - width;
444→  const minY = zones.contentArea.y + captionAbove;
445→  const maxY = zones.contentArea.y + zones.contentArea.height - height - captionBelow;
446→
447→  return {
448→    ...viewport,
449→    ...snapRectToGrid({
450→      x: clamp(viewport.x, zones.contentArea.x, maxX),
451→      y: clamp(viewport.y, minY, Math.max(minY, maxY)),
452→      width,
453→      height,
454→    }),
455→  };
456→}
457→
458→export function getDefaultViewportRect(sheet, source, scale = 100, options = {}) {
459→  const paper = getPaperPreset(sheet.paperSize);
460→  const zones = buildSheetZones(paper);
461→  const bounds = source.bounds || { minX: 0, maxX: 1000, minY: 0, maxY: 1000 };
462→  const sourceWidth = Math.max(1000, bounds.maxX - bounds.minX);
463→  const sourceHeight = Math.max(1000, bounds.maxY - bounds.minY);
464→  const role = options.role || (source.kind === '3d_preview' ? 'supplemental' : 'primary');
465→  const baseScale = sourceFitsFrame(source) ? 1 : Math.max(1, scale);
466→  const width = clamp(
467→    source.kind === '3d_preview'
468→      ? zones.contentArea.width * 0.72
469→      : source.kind === 'roof_schedule'
470→        ? zones.contentArea.width * 0.58
471→      : (sourceWidth / baseScale) + SHEET_TOKENS.viewportPadding * 2,
472→    role === 'primary' ? 120 : 84,
473→    role === 'primary' ? zones.contentArea.width * 0.72 : (source.kind === 'roof_schedule' ? zones.contentArea.width * 0.58 : zones.contentArea.width * 0.44)
474→  );
475→  const height = clamp(
476→    source.kind === '3d_preview'
477→      ? zones.contentArea.height * 0.54
478→      : source.kind === 'roof_schedule'
479→        ? zones.contentArea.height * 0.48
480→      : (sourceHeight / baseScale) + SHEET_TOKENS.viewportPadding * 2,
481→    role === 'primary' ? 96 : 72,
482→    role === 'primary' ? zones.contentArea.height * 0.78 : (source.kind === 'roof_schedule' ? zones.contentArea.height * 0.56 : zones.contentArea.height * 0.42)
483→  );
484→
485→  return snapRectToGrid({
486→    x: zones.contentArea.x + SHEET_TOKENS.viewportGutter,
487→    y: zones.contentArea.y + SHEET_TOKENS.viewportGutter,
488→    width,
489→    height,
490→  });
491→}
