136→function DimensionFields({ part, onUpdate, dispatch, project }) {
137→  const measurement = Math.round(
138→    Math.sqrt(
139→      Math.pow((part.endPoint?.x || 0) - (part.startPoint?.x || 0), 2) +
140→      Math.pow((part.endPoint?.y || 0) - (part.startPoint?.y || 0), 2) +
141→      Math.pow((part.endPoint?.z || 0) - (part.startPoint?.z || 0), 2)
142→    )
143→  );
144→
145→  const handleBoundValueChange = (newVal) => {
146→    if (!part.boundPartId || !part.boundProperty) return;
147→    const boundPart = project.parts.find((p) => p.id === part.boundPartId);
148→    if (!boundPart) return;
149→    const result = applyDimensionValueToPart(part, newVal, boundPart);
150→    if (result) {
151→      dispatch({ type: 'PART_UPDATE', part: { id: result.partId, ...result.changes } });
152→    }
153→  };
154→
155→  const bindableParts = project.parts.filter((p) => p.type !== 'dimension');
156→
157→  const BINDABLE_PROPS = {
158→    panel: ['width', 'depth', 'thickness'],
159→    leg: ['width', 'depth', 'height'],
160→    frame: ['width', 'height', 'length'],
161→    cutout: ['width', 'height', 'depth'],
162→    hole: ['diameter', 'depth'],
163→  };
164→
165→  const handleBind = (partId, property) => {
166→    const target = project.parts.find((p) => p.id === partId);
167→    if (!target) return;
168→    const updated = bindDimensionToPart(part, target, property);
169→    dispatch({ type: 'PART_UPDATE', part: { id: part.id, ...updated } });
170→  };
171→
172→  return (
173→    <>
174→      {part.boundPartId ? (
175→        <NumberInput
176→          label="Value"
177→          value={measurement}
178→          suffix="mm"
179→          onChange={handleBoundValueChange}
180→        />
181→      ) : (
182→        <NumberInput label="Measured" value={measurement} readOnly suffix="mm" onChange={() => {}} />
183→      )}
184→      <NumberInput label="Offset" value={part.offset || 200} onChange={(v) => onUpdate({ offset: v })} />
185→      <TextInput label="Text Override" value={part.textOverride || ''} onChange={(v) => onUpdate({ textOverride: v || null })} />
186→      {part.boundPartId && (
187→        <div className={styles.field}>
188→          <span className={styles.fieldLabel}>Bound to</span>
189→          <span className={styles.typeBadge}>{part.boundProperty || 'part'}</span>
190→        </div>
191→      )}
192→      {!part.boundPartId && bindableParts.length > 0 && (
193→        <BindDimensionUI parts={bindableParts} bindableProps={BINDABLE_PROPS} onBind={handleBind} />
194→      )}
195→    </>
196→  );
197→}
