199→function BindDimensionUI({ parts, bindableProps, onBind }) {
200→  const [selectedPartId, setSelectedPartId] = useState('');
201→  const [selectedProp, setSelectedProp] = useState('');
202→
203→  const selectedPart = parts.find((p) => p.id === selectedPartId);
204→  const props = selectedPart ? (bindableProps[selectedPart.type] || []) : [];
205→
206→  return (
207→    <div className={styles.fieldGroup}>
208→      <span className={styles.groupTitle}>Bind to Part</span>
209→      <select
210→        className={styles.selectInput}
211→        value={selectedPartId}
212→        onChange={(e) => { setSelectedPartId(e.target.value); setSelectedProp(''); }}
213→      >
214→        <option value="">Select part...</option>
215→        {parts.map((p) => (
216→          <option key={p.id} value={p.id}>{p.name} ({p.type})</option>
217→        ))}
218→      </select>
219→      {props.length > 0 && (
220→        <select
221→          className={styles.selectInput}
222→          value={selectedProp}
223→          onChange={(e) => setSelectedProp(e.target.value)}
224→        >
225→          <option value="">Select property...</option>
226→          {props.map((pr) => (
227→            <option key={pr} value={pr}>{pr}</option>
228→          ))}
229→        </select>
230→      )}
231→      {selectedPartId && selectedProp && (
232→        <button
233→          className={styles.duplicateBtn}
234→          onClick={() => onBind(selectedPartId, selectedProp)}
235→        >
236→          Bind
237→        </button>
238→      )}
239→    </div>
240→  );
241→}
