243→function ConstraintsSection({ part, project, dispatch }) {
244→  const [showForm, setShowForm] = useState(false);
245→  const [cType, setCType] = useState('attach_face');
246→  const [targetId, setTargetId] = useState('');
247→  const [srcAnchor, setSrcAnchor] = useState('bottom');
248→  const [tgtAnchor, setTgtAnchor] = useState('top');
249→  const [offset, setOffset] = useState(0);
250→
251→  const constraints = (project.constraints || []).filter(
252→    (c) => c.sourcePartId === part.id || c.targetPartId === part.id
253→  );
254→
255→  const otherParts = project.parts.filter((p) => p.id !== part.id && p.type !== 'dimension');
256→
257→  const handleAddConstraint = () => {
258→    if (!targetId) return;
259→    const constraint = createConstraint({
260→      type: cType,
261→      sourcePartId: part.id,
262→      targetPartId: targetId,
263→      sourceAnchor: srcAnchor,
264→      targetAnchor: tgtAnchor,
265→      offset: parseFloat(offset) || 0,
266→    });
267→    dispatch({ type: 'CONSTRAINT_ADD', constraint });
268→    setShowForm(false);
269→    setTargetId('');
270→  };
271→
272→  return (
273→    <div className={styles.fieldGroup}>
274→      <span className={styles.groupTitle}>Constraints</span>
275→      <div className={styles.constraintSection}>
276→        {constraints.map((c) => {
277→          const targetPart = project.parts.find((p) => p.id === (c.sourcePartId === part.id ? c.targetPartId : c.sourcePartId));
278→          return (
279→            <div key={c.id} className={styles.constraintItem}>
280→              <span>{c.type}: {c.sourceAnchor} → {c.targetAnchor} ({targetPart?.name || '?'})</span>
281→              <button
282→                className={styles.constraintDelete}
283→                onClick={() => dispatch({ type: 'CONSTRAINT_DELETE', constraintId: c.id })}
284→                title="Remove constraint"
285→              >
286→                ×
287→              </button>
288→            </div>
289→          );
290→        })}
291→      </div>
292→
293→      {!showForm ? (
294→        <button className={styles.duplicateBtn} onClick={() => setShowForm(true)}>
295→          Add Constraint
296→        </button>
297→      ) : (
298→        <div className={styles.constraintSection}>
299→          <SelectInput label="Type" value={cType} options={CONSTRAINT_TYPES} onChange={setCType} />
300→          <label className={styles.field}>
301→            <span className={styles.fieldLabel}>Target</span>
302→            <select className={styles.selectInput} value={targetId} onChange={(e) => setTargetId(e.target.value)}>
303→              <option value="">Select...</option>
304→              {otherParts.map((p) => (
305→                <option key={p.id} value={p.id}>{p.name} ({p.type})</option>
306→              ))}
307→            </select>
308→          </label>
309→          <SelectInput label="Source Anchor" value={srcAnchor} options={ANCHOR_OPTIONS} onChange={setSrcAnchor} />
310→          <SelectInput label="Target Anchor" value={tgtAnchor} options={ANCHOR_OPTIONS} onChange={setTgtAnchor} />
311→          <NumberInput label="Offset" value={offset} suffix="mm" onChange={setOffset} />
312→          <div style={{ display: 'flex', gap: '4px' }}>
313→            <button className={styles.duplicateBtn} onClick={handleAddConstraint}>Create</button>
314→            <button className={styles.duplicateBtn} onClick={() => setShowForm(false)}>Cancel</button>
315→          </div>
316→        </div>
317→      )}
318→    </div>
319→  );
320→}
