320→            project={project}
321→            sheet={sheet}
322→            selectedId={null}
323→            selectedType={null}
324→          />
325→        </svg>
326→      )}
327→      <div className={styles.statusBar}>
328→        <span>Workspace: sheet</span>
329→        <span>Sheet: {sheet?.title || 'None'}</span>
330→        <span>Zoom: {Math.round(viewport.zoom * 100)}%</span>
331→      </div>
332→    </div>
