import { buildElevationAnnotationScene } from '@/elevations/annotations';
import { buildProjectElevationScene, buildRoofOnlyElevationScene } from '@/elevations/scene';
import { getDefaultActiveFloorId, resolveProjectFloor } from '@/domain/floorModels';
import { resolveRoofSectionCut } from '@/domain/roofModels';
import { getProjectTrussSystems } from '@/domain/trussModels';
import { filterFloorByPhase, filterProjectByPhase } from '@/domain/phaseFilter';
import { getBeamRenderData } from '@/geometry/beamGeometry';
import { columnOutline } from '@/geometry/columnGeometry';
import { landingOutline } from '@/geometry/landingGeometry';
import { getSectionCutRenderData } from '@/geometry/sectionCutGeometry';
import { getSlabRenderData } from '@/geometry/slabGeometry';
import { getStairRenderData } from '@/geometry/stairGeometry';
import { fixtureOutline } from '@/geometry/fixtureGeometry';
import { doorOutlineOnWall, windowOutlineOnWall } from '@/geometry/wallGeometry';
import { getWallRenderData } from '@/geometry/wallColumnGeometry';
import { buildRoofPlanBounds } from '@/geometry/roofPlanGeometry';
import { buildRoofPlanScene } from '@/geometry/roofPlanScene';
import { buildFloorTrussGeometry, buildTrussDetailScene } from '@/geometry/trussGeometry';
import { buildRoofScheduleSummary } from '@/roof/roofSchedule';
import { buildRoofScheduleLayout } from '@/roof/roofScheduleLayout';
import { buildProjectSectionScene } from '@/sections/scene';

const PLAN_PADDING = 1500;
const VERTICAL_PADDING = 700;
const TOP_PADDING = 1100;

function boundsFromPoints(points = [], fallback = { minX: -1000, maxX: 1000, minY: -1000, maxY: 1000 }) {
  if (!points.length) return fallback;
  return {
    minX: Math.min(...points.map((point) => point.x)),
    maxX: Math.max(...points.map((point) => point.x)),
    minY: Math.min(...points.map((point) => point.y)),
    maxY: Math.max(...points.map((point) => point.y)),
  };
}

function expandBounds(bounds, paddingX, paddingY = paddingX) {
  return {
    minX: bounds.minX - paddingX,
    maxX: bounds.maxX + paddingX,
    minY: bounds.minY - paddingY,
    maxY: bounds.maxY + paddingY,
  };
}

function collectPlanPoints(floor) {
  const points = [];

  for (const wall of floor.walls || []) {
    points.push(...(getWallRenderData(wall, floor.columns || []).outline || []));
  }
  for (const room of floor.rooms || []) {
    points.push(...(room.points || []));
  }
  for (const beam of floor.beams || []) {
    const renderData = getBeamRenderData(beam, floor.columns || []);
    if (renderData?.outline) points.push(...renderData.outline);
  }
  for (const stair of floor.stairs || []) {
    const renderData = getStairRenderData(stair);
    if (renderData?.outline) points.push(...renderData.outline);
  }
  for (const landing of floor.landings || []) {
    points.push(...landingOutline(landing));
  }
  for (const column of floor.columns || []) {
    points.push(...columnOutline(column));
  }
  for (const slab of (floor.slabs || [])) {
    const rd = getSlabRenderData(slab);
    if (rd?.boundaryPoints) points.push(...rd.boundaryPoints);
  }
  for (const sc of (floor.sectionCuts || [])) {
    points.push(sc.startPoint, sc.endPoint);
    const renderData = getSectionCutRenderData(sc);
    if (renderData?.arrow) {
      points.push(renderData.arrow.shaftStart, renderData.arrow.shaftEnd, renderData.arrow.headA, renderData.arrow.headB);
    }
  }

  for (const door of floor.doors || []) {
    const wall = (floor.walls || []).find((entry) => entry.id === door.wallId);
    if (!wall) continue;
    const outline = doorOutlineOnWall(wall, door);
    points.push(outline.p1, outline.p2, outline.p3, outline.p4);
  }

  for (const windowItem of floor.windows || []) {
    const wall = (floor.walls || []).find((entry) => entry.id === windowItem.wallId);
    if (!wall) continue;
    const outline = windowOutlineOnWall(wall, windowItem);
    points.push(outline.p1, outline.p2, outline.p3, outline.p4);
  }

  for (const fixture of floor.fixtures || []) {
    points.push(...fixtureOutline(fixture));
  }

  return points;
}

function buildPlanSource(floor) {
  if (!floor) {
    return {
      kind: 'empty',
      title: 'Plan',
      message: 'Missing floor.',
      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
    };
  }

  const geometryBounds = expandBounds(boundsFromPoints(collectPlanPoints(floor)), PLAN_PADDING);

  return {
    kind: 'plan',
    title: `${floor.name} Plan`,
    floor,
    bounds: geometryBounds,
  };
}

function sceneBoundsToRenderBounds(scene) {
  return {
    minX: scene.bounds.minX - VERTICAL_PADDING,
    maxX: scene.bounds.maxX + VERTICAL_PADDING,
    minY: -scene.bounds.maxZ - TOP_PADDING,
    maxY: -scene.bounds.minZ + VERTICAL_PADDING,
  };
}

function buildSectionSource(project, floor, sourceRefId) {
  const cuts = floor?.sectionCuts || [];
  const sectionCut = sourceRefId
    ? cuts.find(s => s.id === sourceRefId)
    : cuts[0] || null;

  if (!sectionCut) {
    return {
      kind: 'empty',
      title: 'Section',
      message: 'No section cut on this floor.',
      bounds: { minX: 0, maxX: 2000, minY: -3000, maxY: 1000 },
    };
  }

  const scene = buildProjectSectionScene(project, floor.id, sectionCut.id);
  return {
    kind: 'section',
    title: sectionCut.label || 'Section',
    floor,
    scene,
    bounds: sceneBoundsToRenderBounds(scene),
  };
}

function buildElevationSource(project, floor, sourceView) {
  if (!floor) {
    return {
      kind: 'empty',
      title: 'Elevation',
      message: 'Missing floor.',
      bounds: { minX: 0, maxX: 2000, minY: -3000, maxY: 1000 },
    };
  }

  const scene = buildProjectElevationScene(project, floor.id, sourceView);
  const annotationScene = buildElevationAnnotationScene(floor, scene);

  return {
    kind: 'elevation',
    title: scene.title,
    floor,
    viewMode: sourceView,
    scene,
    annotationScene,
    bounds: sceneBoundsToRenderBounds(scene),
  };
}

function normalizeRoofElevationSourceView(sourceView) {
  if (sourceView === 'roof_elevation_front') return 'elevation_front';
  if (sourceView === 'roof_elevation_rear') return 'elevation_rear';
  if (sourceView === 'roof_elevation_left') return 'elevation_left';
  if (sourceView === 'roof_elevation_right') return 'elevation_right';
  return 'elevation_front';
}

function buildRoofElevationSource(project, sourceView) {
  const roofSystem = project?.roofSystem || null;
  if (!roofSystem) {
    return {
      kind: 'empty',
      title: 'Roof Elevation',
      message: 'No roof system in this project.',
      bounds: { minX: 0, maxX: 2000, minY: -3000, maxY: 1000 },
    };
  }

  const scene = buildRoofOnlyElevationScene(roofSystem, normalizeRoofElevationSourceView(sourceView));
  return {
    kind: 'roof_elevation',
    title: scene.title,
    roofSystem,
    viewMode: sourceView,
    scene,
    bounds: sceneBoundsToRenderBounds(scene),
  };
}

function build3DPreviewSource(project, floor) {
  if (!floor) {
    return {
      kind: 'empty',
      title: 'Axonometric View',
      message: 'Missing floor.',
      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
    };
  }

  // Use 16:10 aspect ratio matching render resolution (1600x1000).
  // At scale 100, this fills a 160x100mm viewport on paper.
  const imageWidth = 16000;
  const imageHeight = 10000;

  return {
    kind: '3d_preview',
    title: 'Axonometric View',
    project,
    activeFloorId: floor.id,
    bounds: {
      minX: 0,
      maxX: imageWidth,
      minY: 0,
      maxY: imageHeight,
    },
  };
}

function buildRoofPlanSource(project) {
  const roofSystem = project?.roofSystem || null;
  if (!roofSystem) {
    return {
      kind: 'empty',
      title: 'Roof Plan',
      message: 'No roof system in this project.',
      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
    };
  }

  return {
    kind: 'roof_plan',
    title: roofSystem.name ? `${roofSystem.name} Plan` : 'Roof Plan',
    roofSystem,
    bounds: buildRoofPlanScene(roofSystem).bounds,
  };
}

function buildRoofDrainageSource(project) {
  const roofSystem = project?.roofSystem || null;
  if (!roofSystem) {
    return {
      kind: 'empty',
      title: 'Roof Drainage',
      message: 'No roof system in this project.',
      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
    };
  }

  return {
    kind: 'roof_drainage',
    title: roofSystem.name ? `${roofSystem.name} Drainage` : 'Roof Drainage',
    roofSystem,
    bounds: buildRoofPlanBounds(roofSystem),
  };
}

function buildTrussPlanSource(project, sourceFloorId) {
  const floor = resolveProjectFloor(project, sourceFloorId);
  const trussSystems = getProjectTrussSystems(project, sourceFloorId);
  if (!floor || !trussSystems.length) {
    return {
      kind: 'empty',
      title: 'Truss Plan',
      message: 'No truss systems on this floor.',
      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
    };
  }

  const trussGeometry = buildFloorTrussGeometry(trussSystems);
  const floorBounds = expandBounds(boundsFromPoints(collectPlanPoints(floor)), PLAN_PADDING);
  return {
    kind: 'truss_plan',
    title: `${floor.name} Truss Plan`,
    floor,
    trussSystems,
    bounds: {
      minX: Math.min(floorBounds.minX, trussGeometry.bounds.minX),
      maxX: Math.max(floorBounds.maxX, trussGeometry.bounds.maxX),
      minY: Math.min(floorBounds.minY, trussGeometry.bounds.minY),
      maxY: Math.max(floorBounds.maxY, trussGeometry.bounds.maxY),
    },
  };
}

function buildTrussDetailSource(project, sourceFloorId, sourceRefId = null) {
  const trussSystems = getProjectTrussSystems(project, sourceFloorId);
  const trussDetailRef = sourceRefId
    ? trussSystems.find((trussSystem) => (
        (trussSystem.trussInstances || []).some((trussInstance) => trussInstance.id === sourceRefId)
      )) || null
    : trussSystems[0] || null;
  const trussInstanceId = sourceRefId
    || trussDetailRef?.trussInstances?.[0]?.id
    || null;
  if (!trussDetailRef || !trussInstanceId) {
    return {
      kind: 'empty',
      title: 'Truss Detail',
      message: 'No truss detail is available for this floor.',
      bounds: { minX: 0, maxX: 2000, minY: -3000, maxY: 1000 },
    };
  }

  const detailScene = buildTrussDetailScene(trussDetailRef, trussInstanceId);
  if (!detailScene) {
    return {
      kind: 'empty',
      title: 'Truss Detail',
      message: 'No truss detail is available for this floor.',
      bounds: { minX: 0, maxX: 2000, minY: -3000, maxY: 1000 },
    };
  }

  return {
    kind: 'truss_detail',
    title: detailScene.title,
    trussSystem: trussDetailRef,
    trussInstanceId,
    detailScene,
    bounds: {
      minX: detailScene.bounds.minX,
      maxX: detailScene.bounds.maxX,
      minY: -detailScene.bounds.maxZ,
      maxY: -detailScene.bounds.minZ,
    },
  };
}

function buildRoofSectionSource(project, sourceFloorId, sourceRefId) {
  const roofSystem = project?.roofSystem || null;
  if (!roofSystem) {
    return {
      kind: 'empty',
      title: 'Roof Section',
      message: 'No roof system in this project.',
      bounds: { minX: 0, maxX: 2000, minY: -3000, maxY: 1000 },
    };
  }

  const { floor, sectionCut } = resolveRoofSectionCut(project, sourceFloorId, sourceRefId);
  if (!floor || !sectionCut) {
    return {
      kind: 'empty',
      title: 'Roof Section',
      message: 'No section cut is available for the roof.',
      bounds: { minX: 0, maxX: 2000, minY: -3000, maxY: 1000 },
    };
  }

  const scene = buildProjectSectionScene(project, floor.id, sectionCut.id);
  return {
    kind: 'roof_section',
    title: `Roof ${sectionCut.label || 'Section'}`,
    roofSystem,
    sourceFloor: floor,
    scene,
    bounds: sceneBoundsToRenderBounds(scene),
  };
}

function buildRoofScheduleSource(project) {
  const roofSystem = project?.roofSystem || null;
  if (!roofSystem) {
    return {
      kind: 'empty',
      title: 'Roof Schedule',
      message: 'No roof system in this project.',
      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1400 },
    };
  }

  const schedule = buildRoofScheduleSummary(roofSystem);
  const layout = buildRoofScheduleLayout(schedule, { showTitle: false });

  return {
    kind: 'roof_schedule',
    title: schedule.title,
    roofSystem,
    schedule,
    bounds: layout.bounds,
  };
}

export function resolveSheetViewportSource(project, viewport, phaseContext) {
  const defaultFloorId = getDefaultActiveFloorId(project, viewport.sourceFloorId);
  let effectiveProject = project;
  let floor = resolveProjectFloor(project, defaultFloorId);

  if (phaseContext?.activePhaseId && phaseContext?.phaseViewMode && phaseContext.phaseViewMode !== 'all') {
    effectiveProject = filterProjectByPhase(project, phaseContext.activePhaseId, phaseContext.phaseViewMode);
    floor = resolveProjectFloor(effectiveProject, defaultFloorId);
  }

  switch (viewport.sourceView) {
    case 'truss_plan':
      return buildTrussPlanSource(effectiveProject, defaultFloorId);
    case 'truss_detail':
      return buildTrussDetailSource(effectiveProject, defaultFloorId, viewport.sourceRefId);
    case 'roof_plan':
      return buildRoofPlanSource(effectiveProject);
    case 'roof_drainage':
      return buildRoofDrainageSource(effectiveProject);
    case 'roof_elevation_front':
    case 'roof_elevation_rear':
    case 'roof_elevation_left':
    case 'roof_elevation_right':
      return buildRoofElevationSource(effectiveProject, viewport.sourceView);
    case 'roof_section':
      return buildRoofSectionSource(effectiveProject, defaultFloorId, viewport.sourceRefId);
    case 'roof_schedule':
      return buildRoofScheduleSource(effectiveProject);
    case '3d_preview':
      return build3DPreviewSource(effectiveProject, floor);
    case 'section':
      return buildSectionSource(effectiveProject, floor, viewport.sourceRefId);
    case 'elevation_front':
    case 'elevation_rear':
    case 'elevation_left':
    case 'elevation_right':
      return buildElevationSource(effectiveProject, floor, viewport.sourceView);
    case 'plan':
    default:
      return buildPlanSource(floor);
  }
}

export function getViewportSourceLabel(sourceView) {
  switch (sourceView) {
    case 'truss_plan':
      return 'Truss Plan';
    case 'truss_detail':
      return 'Truss Detail';
    case 'roof_plan':
      return 'Roof Plan';
    case 'roof_drainage':
      return 'Roof Drainage';
    case 'roof_elevation_front':
      return 'Roof Front Elevation';
    case 'roof_elevation_rear':
      return 'Roof Rear Elevation';
    case 'roof_elevation_left':
      return 'Roof Left Elevation';
    case 'roof_elevation_right':
      return 'Roof Right Elevation';
    case 'roof_section':
      return 'Roof Section';
    case 'roof_schedule':
      return 'Roof Schedule';
    case '3d_preview':
      return 'Axonometric View';
    case 'section':
      return 'Section';
    case 'elevation_front':
      return 'Front Elevation';
    case 'elevation_rear':
      return 'Rear Elevation';
    case 'elevation_left':
      return 'Left Elevation';
    case 'elevation_right':
      return 'Right Elevation';
    case 'plan':
    default:
      return 'Plan';
  }
}

