  if (parts.length === 0) {
    return {
      kind: 'empty',
      title: `${resolveAssemblyName(project, assemblyId)} — ${view}`,
      message: 'No parts in this assembly.',
      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
    };
  }

  const bounds = getPartsBounds(parts, view, dimensions);

  return {
    kind: 'sketch_assembly',
    title: `${resolveAssemblyName(project, assemblyId)} — ${view}`,
    view,
    parts,
    dimensions,
    assembly: assemblyId ? (project.assemblies || []).find((a) => a.id === assemblyId) : null,
    bounds,
  };
}

function buildSketchPartDetailSource(project, partId) {
  const part = project.parts.find((p) => p.id === partId);
  if (!part || part.type === 'dimension') {
    return {
      kind: 'empty',
      title: 'Part Detail',
      message: 'Part not found.',
      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
    };
  }

  const ext = getPartExtents(part);
  const views = ['top', 'front', 'side'];
  const viewLayouts = [];

  // Compute auto-dimension descriptors for each view
  let totalWidth = 0;
  const viewBounds = views.map((view) => {
    const { svgX, svgY, svgWidth, svgHeight } = projectPartToView(part, view);
    return { view, svgX, svgY, svgWidth, svgHeight };
  });

  // Layout: top | front | side arranged horizontally with gaps
  let offsetX = 0;
  for (const vb of viewBounds) {
    viewLayouts.push({
      view: vb.view,
      offsetX,
      offsetY: 0,
      width: vb.svgWidth,
      height: vb.svgHeight,
      svgX: vb.svgX,
      svgY: vb.svgY,
    });
    offsetX += vb.svgWidth + VIEW_GAP;
  }
  totalWidth = offsetX - VIEW_GAP;

  const maxHeight = Math.max(...viewBounds.map((vb) => vb.svgHeight));
  const padding = PART_PADDING;

  return {
    kind: 'sketch_part_detail',
    title: part.name || 'Part Detail',
    part,
    extents: ext,
    viewLayouts,
    bounds: {
      minX: -padding,
      maxX: totalWidth + padding,
      minY: -padding,
      maxY: maxHeight + padding,
    },
  };
}

function buildSketchPartListSource(project, assemblyId) {
  const parts = gatherAssemblyParts(project, assemblyId);

  // Build BOM rows — group identical parts by name+type+material+dimensions
  const groupMap = new Map();
  for (const part of parts) {
    const ext = getPartExtents(part);
    const key = `${part.type}|${part.material || ''}|${ext.width}|${ext.depth}|${ext.height}`;
    if (groupMap.has(key)) {
      groupMap.get(key).qty += 1;
    } else {
      groupMap.set(key, {
        name: part.name,
        type: part.type,
        material: part.material || '-',
        width: ext.width,
        depth: ext.depth,
        height: ext.height,
        qty: 1,
      });
    }
  }

  const rows = [];
  let item = 1;
  for (const group of groupMap.values()) {
    rows.push({
      item: item++,
      name: group.name,
      type: group.type,
      material: group.material,
      qty: group.qty,
      dims: `${Math.round(group.width)} x ${Math.round(group.depth)} x ${Math.round(group.height)}`,
    });
  }

  const columnWidths = [30, 120, 60, 80, 30, 120];
  const tableWidth = columnWidths.reduce((sum, w) => sum + w, 0);
  const rowHeight = 20;
  const headerHeight = 24;
  const tableHeight = headerHeight + rows.length * rowHeight;

  return {
    kind: 'sketch_part_list',
    title: `${resolveAssemblyName(project, assemblyId)} Parts List`,
    rows,
    columnWidths,
    headers: ['Item', 'Name', 'Type', 'Material', 'Qty', 'Dimensions'],
    rowHeight,
    headerHeight,
    bounds: {
      minX: 0,
      maxX: tableWidth,
      minY: 0,
      maxY: tableHeight,
    },
  };
}

export function resolveSketchViewportSource(sketchProject, viewport) {
  const { sourceView, sourceRefId } = viewport;

  if (sourceView === 'sketch_assembly_top' || sourceView === 'sketch_assembly_front' || sourceView === 'sketch_assembly_side') {
    const view = extractView(sourceView);
    return buildSketchAssemblySource(sketchProject, sourceRefId, view);
  }

  if (sourceView === 'sketch_part_detail') {
    return buildSketchPartDetailSource(sketchProject, sourceRefId);
  }

  if (sourceView === 'sketch_part_list') {
    return buildSketchPartListSource(sketchProject, sourceRefId);
  }

  return {
    kind: 'empty',
    title: 'Unknown Source',
    message: `Unknown source view: ${sourceView}`,
    bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
  };
}

export function getSketchViewportSourceLabel(sourceView) {
  switch (sourceView) {
    case 'sketch_assembly_top': return 'Assembly Top';
    case 'sketch_assembly_front': return 'Assembly Front';
    case 'sketch_assembly_side': return 'Assembly Side';
    case 'sketch_part_detail': return 'Part Detail';
    case 'sketch_part_list': return 'Parts List';
    default: return 'Unknown';
  }
}

