    </g>
  );
}

function PartListContent({ source }) {
  const { rows, columnWidths, headers, rowHeight, headerHeight, bounds } = source;
  const tableWidth = bounds.maxX - bounds.minX;

  let colX = 0;
  const colPositions = columnWidths.map((w) => {
    const x = colX;
    colX += w;
    return x;
  });

  return (
    <g>
      {/* Table border */}
      <rect
        x={0} y={0}
        width={tableWidth}
        height={headerHeight + rows.length * rowHeight}
        fill="none"
        stroke={SHEET_COLORS.border}
        strokeWidth={0.5}
      />
      {/* Header row */}
      <rect
        x={0} y={0}
        width={tableWidth} height={headerHeight}
        fill={SHEET_COLORS.panelFill}
        stroke={SHEET_COLORS.border}
        strokeWidth={0.3}
      />
      {headers.map((header, i) => (
        <text
          key={`hdr-${i}`}
          x={colPositions[i] + columnWidths[i] / 2}
          y={headerHeight / 2}
          textAnchor="middle"
          dominantBaseline="central"
          fontSize={8}
          fontWeight={600}
          fill={SHEET_COLORS.text}
          letterSpacing={0.3}
        >
          {header}
        </text>
      ))}
      {/* Column dividers */}
      {colPositions.slice(1).map((x, i) => (
        <line
          key={`col-${i}`}
          x1={x} y1={0}
          x2={x} y2={headerHeight + rows.length * rowHeight}
          stroke={SHEET_COLORS.divider}
          strokeWidth={0.2}
        />
      ))}
      {/* Data rows */}
      {rows.map((row, rowIndex) => {
        const y = headerHeight + rowIndex * rowHeight;
        const values = [
          String(row.item),
          row.name,
          row.type,
          row.material,
          String(row.qty),
          row.dims,
        ];
        return (
          <g key={`row-${rowIndex}`}>
            <line
              x1={0} y1={y}
              x2={tableWidth} y2={y}
              stroke={SHEET_COLORS.divider}
              strokeWidth={0.15}
            />
            {values.map((val, colIndex) => (
              <text
                key={`cell-${rowIndex}-${colIndex}`}
                x={colPositions[colIndex] + columnWidths[colIndex] / 2}
                y={y + rowHeight / 2}
                textAnchor="middle"
                dominantBaseline="central"
                fontSize={7}
                fill={SHEET_COLORS.text}
              >
                {val}
              </text>
            ))}
          </g>
        );
      })}
    </g>
  );
}

export default function SketchSheetViewportContent({ source }) {
  if (!source || source.kind === 'empty') return null;

  if (source.kind === 'sketch_assembly') {
    return <AssemblyViewContent source={source} />;
  }

  if (source.kind === 'sketch_part_detail') {
    return <PartDetailContent source={source} />;
  }

  if (source.kind === 'sketch_part_list') {
    return <PartListContent source={source} />;
  }

  return null;
}

