import { lazy, Suspense, useEffect } from 'react';
import { SketchProvider, useSketch } from './app/SketchProvider';
import { SketchEditorProvider, useSketchEditor } from './app/SketchEditorProvider';
import SketchToolbar from './ui/SketchToolbar';
import SketchSidebar from './ui/SketchSidebar';
import SketchCanvas from './renderers/SketchCanvas';
import SketchPropertiesPanel from './ui/SketchPropertiesPanel';
import { saveSketchProject } from './persistence/sketchStorage';
import styles from './SketchWorkspace.module.css';

const SketchPreviewPanel = lazy(() => import('./renderers/SketchPreviewPanel'));
const SketchSheetCanvas = lazy(() => import('./renderers/SketchSheetCanvas'));

function SketchInner() {
  const { project, isDirty, dispatch } = useSketch();
  const { maximizedPanel, dispatch: editorDispatch } = useSketchEditor();

  // Autosave
  useEffect(() => {
    if (!isDirty) return;
    const timer = setTimeout(() => {
      saveSketchProject(project);
      dispatch({ type: 'MARK_SAVED' });
    }, 5000);
    return () => clearTimeout(timer);
  }, [isDirty, project, dispatch]);

  return (
    <div className={styles.layout}>
      <div className={styles.toolbar}>
        <SketchToolbar />
      </div>
      <div className={styles.sidebar}>
        <SketchSidebar />
      </div>
      <div className={styles.canvas}>
        <div className={`${styles.modelWorkspace} ${maximizedPanel ? styles.workspaceMaximized : ''}`}>
          {maximizedPanel !== 'preview' && (
            <div className={styles.primaryCanvas}>
              <SketchCanvas />
            </div>
          )}
          {maximizedPanel !== 'canvas' && (
            <div className={styles.preview}>
              <Suspense fallback={<div className={styles.previewFallback}>Loading 3D preview...</div>}>
                <SketchPreviewPanel
                  isMaximized={maximizedPanel === 'preview'}
                  onToggleMaximize={() => editorDispatch({ type: 'TOGGLE_MAXIMIZE_PANEL', panel: 'preview' })}
                />
              </Suspense>
            </div>
          )}
        </div>
      </div>
      <div className={styles.rightPanel}>
        <SketchPropertiesPanel />
      </div>
    </div>
  );
}

export default function SketchWorkspace({ initialProject }) {
  return (
    <div className="editorRoot">
      <SketchProvider initialProject={initialProject}>
        <SketchEditorProvider>
          <SketchInner />
        </SketchEditorProvider>
      </SketchProvider>
    </div>
  );
}

