 1→import { lazy, Suspense, useEffect } from 'react';
 2→import { SketchProvider, useSketch } from './app/SketchProvider';
 3→import { SketchEditorProvider, useSketchEditor } from './app/SketchEditorProvider';
 4→import SketchToolbar from './ui/SketchToolbar';
 5→import SketchSidebar from './ui/SketchSidebar';
 6→import SketchCanvas from './renderers/SketchCanvas';
 7→import SketchPropertiesPanel from './ui/SketchPropertiesPanel';
 8→import { saveSketchProject } from './persistence/sketchStorage';
 9→import styles from './SketchWorkspace.module.css';
10→
11→const SketchPreviewPanel = lazy(() => import('./renderers/SketchPreviewPanel'));
12→const SketchSheetCanvas = lazy(() => import('./renderers/SketchSheetCanvas'));
13→
14→function SketchInner() {
15→  const { project, isDirty, dispatch } = useSketch();
16→  const { maximizedPanel, workspaceMode, activeSheetId, dispatch: editorDispatch } = useSketchEditor();
17→
18→  // Autosave
19→  useEffect(() => {
20→    if (!isDirty) return;
21→    const timer = setTimeout(() => {
22→      saveSketchProject(project);
23→      dispatch({ type: 'MARK_SAVED' });
24→    }, 5000);
25→    return () => clearTimeout(timer);
26→  }, [isDirty, project, dispatch]);
27→
28→  // If active sheet was deleted, revert to model mode
29→  useEffect(() => {
30→    if (workspaceMode === 'sheet' && activeSheetId) {
31→      const sheetExists = (project.sheets || []).some((s) => s.id === activeSheetId);
32→      if (!sheetExists) {
33→        editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
34→        editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: null });
35→      }
36→    }
37→  }, [workspaceMode, activeSheetId, project.sheets, editorDispatch]);
38→
39→  const isSheetMode = workspaceMode === 'sheet';
40→
41→  return (
42→    <div className={styles.layout}>
43→      <div className={styles.toolbar}>
44→        <SketchToolbar />
45→      </div>
46→      <div className={styles.sidebar}>
47→        <SketchSidebar />
48→      </div>
49→      <div className={styles.canvas}>
50→        {isSheetMode ? (
51→          <Suspense fallback={<div className={styles.previewFallback}>Loading sheet...</div>}>
52→            <SketchSheetCanvas />
53→          </Suspense>
54→        ) : (
55→          <div className={`${styles.modelWorkspace} ${maximizedPanel ? styles.workspaceMaximized : ''}`}>
56→            {maximizedPanel !== 'preview' && (
57→              <div className={styles.primaryCanvas}>
58→                <SketchCanvas />
59→              </div>
60→            )}
61→            {maximizedPanel !== 'canvas' && (
62→              <div className={styles.preview}>
63→                <Suspense fallback={<div className={styles.previewFallback}>Loading 3D preview...</div>}>
64→                  <SketchPreviewPanel
65→                    isMaximized={maximizedPanel === 'preview'}
