  4→export function validateProjectStructure(project) {
  5→  const errors = [];
  6→
  7→  if (!project || typeof project !== 'object') {
  8→    errors.push({ path: '', message: 'Project must be a non-null object' });
  9→    return errors;
 10→  }
 11→  if (typeof project.id !== 'string' || !project.id) {
 12→    errors.push({ path: 'id', message: 'Project must have a non-empty string id' });
 13→  }
 14→  if (typeof project.name !== 'string' || !project.name) {
 15→    errors.push({ path: 'name', message: 'Project must have a non-empty string name' });
 16→  }
 17→  if (!Array.isArray(project.floors) || project.floors.length === 0) {
 18→    errors.push({ path: 'floors', message: 'Project must have a non-empty floors array' });
 19→    return errors;
 20→  }
 21→
 22→  project.floors.forEach((floor, fi) => {
 23→    if (!floor.id) {
 24→      errors.push({ path: `floors[${fi}].id`, message: 'Floor must have an id' });
 25→    }
 26→    if (!Array.isArray(floor.walls)) {
 27→      errors.push({ path: `floors[${fi}].walls`, message: 'Floor must have a walls array' });
 28→    }
 29→
 30→    for (const door of (floor.doors || [])) {
 31→      if (!door.id) errors.push({ path: `floors[${fi}].doors`, message: 'Door missing id' });
 32→      if (!door.wallId) errors.push({ path: `floors[${fi}].doors`, message: `Door ${door.id || '?'} missing wallId` });
 33→    }
 34→
 35→    for (const win of (floor.windows || [])) {
 36→      if (!win.id) errors.push({ path: `floors[${fi}].windows`, message: 'Window missing id' });
 37→      if (!win.wallId) errors.push({ path: `floors[${fi}].windows`, message: `Window ${win.id || '?'} missing wallId` });
 38→    }
 39→  });
 40→
 41→  return errors;
 42→}
