 44→export function validateProjectReferences(project) {
 45→  const warnings = [];
 46→
 47→  const floorIds = new Set(project.floors.map((f) => f.id));
 48→  const phaseIds = new Set((project.phases || []).map((p) => p.id));
 49→
 50→  for (const floor of project.floors) {
 51→    const wallIds = new Set((floor.walls || []).map((w) => w.id));
 52→    const landingIds = new Set((floor.landings || []).map((l) => l.id));
 53→    const columnIds = new Set((floor.columns || []).map((c) => c.id));
 54→
 55→    for (const door of (floor.doors || [])) {
 56→      if (door.wallId && !wallIds.has(door.wallId)) {
 57→        warnings.push({ path: `floor ${floor.id} door ${door.id}`, message: `References non-existent wall ${door.wallId}` });
 58→      }
 59→    }
 60→
 61→    for (const win of (floor.windows || [])) {
 62→      if (win.wallId && !wallIds.has(win.wallId)) {
 63→        warnings.push({ path: `floor ${floor.id} window ${win.id}`, message: `References non-existent wall ${win.wallId}` });
 64→      }
 65→    }
 66→
 67→    for (const beam of (floor.beams || [])) {
 68→      if (beam.startRef?.columnId && !columnIds.has(beam.startRef.columnId)) {
 69→        warnings.push({ path: `floor ${floor.id} beam ${beam.id}`, message: `startRef references non-existent column ${beam.startRef.columnId}` });
 70→      }
 71→      if (beam.endRef?.columnId && !columnIds.has(beam.endRef.columnId)) {
 72→        warnings.push({ path: `floor ${floor.id} beam ${beam.id}`, message: `endRef references non-existent column ${beam.endRef.columnId}` });
 73→      }
 74→    }
 75→
 76→    for (const stair of (floor.stairs || [])) {
 77→      if (stair.floorRelation?.fromFloorId && !floorIds.has(stair.floorRelation.fromFloorId)) {
 78→        warnings.push({ path: `floor ${floor.id} stair ${stair.id}`, message: `fromFloorId references non-existent floor ${stair.floorRelation.fromFloorId}` });
 79→      }
 80→      if (stair.floorRelation?.toFloorId && !floorIds.has(stair.floorRelation.toFloorId)) {
 81→        warnings.push({ path: `floor ${floor.id} stair ${stair.id}`, message: `toFloorId references non-existent floor ${stair.floorRelation.toFloorId}` });
 82→      }
 83→      if (stair.startLandingAttachment?.landingId && !landingIds.has(stair.startLandingAttachment.landingId)) {
 84→        warnings.push({ path: `floor ${floor.id} stair ${stair.id}`, message: `startLandingAttachment references non-existent landing ${stair.startLandingAttachment.landingId}` });
 85→      }
 86→      if (stair.endLandingAttachment?.landingId && !landingIds.has(stair.endLandingAttachment.landingId)) {
 87→        warnings.push({ path: `floor ${floor.id} stair ${stair.id}`, message: `endLandingAttachment references non-existent landing ${stair.endLandingAttachment.landingId}` });
 88→      }
 89→    }
 90→
 91→    for (const slab of (floor.slabs || [])) {
 92→      if (slab.floorId && !floorIds.has(slab.floorId)) {
 93→        warnings.push({ path: `floor ${floor.id} slab ${slab.id}`, message: `floorId references non-existent floor ${slab.floorId}` });
 94→      }
 95→    }
 96→
 97→    // Check phaseId references on all phase-assignable objects
 98→    for (const key of PHASE_ASSIGNABLE_KEYS) {
 99→      for (const obj of (floor[key] || [])) {
100→        if (obj.phaseId && !phaseIds.has(obj.phaseId)) {
101→          warnings.push({ path: `floor ${floor.id} ${key} ${obj.id}`, message: `phaseId references non-existent phase ${obj.phaseId}` });
102→        }
103→      }
104→    }
105→  }
106→
107→  // Check phaseId on roof system and truss systems
108→  if (project.roofSystem?.phaseId && !phaseIds.has(project.roofSystem.phaseId)) {
109→    warnings.push({ path: 'roofSystem', message: `phaseId references non-existent phase ${project.roofSystem.phaseId}` });
110→  }
111→  for (const ts of (project.trussSystems || [])) {
112→    if (ts.phaseId && !phaseIds.has(ts.phaseId)) {
113→      warnings.push({ path: `trussSystem ${ts.id}`, message: `phaseId references non-existent phase ${ts.phaseId}` });
114→    }
115→  }
116→
117→  // Check viewport phaseId references
118→  for (const sheet of (project.sheets || [])) {
119→    for (const vp of (sheet.viewports || [])) {
120→      if (vp.phaseId && !phaseIds.has(vp.phaseId)) {
121→        warnings.push({ path: `sheet ${sheet.id} viewport ${vp.id}`, message: `phaseId references non-existent phase ${vp.phaseId}` });
122→      }
123→    }
124→  }
125→
126→  return warnings;
127→}
