 1→const migrations = new Map();
 2→
 3→export function registerMigration(fromVersion, toVersion, migrateFn) {
 4→  migrations.set(fromVersion, { toVersion, migrate: migrateFn });
 5→}
 6→
 7→export function runMigrations(project, fromSchemaVersion, targetSchemaVersion) {
 8→  let current = fromSchemaVersion;
 9→  let result = project;
10→
11→  while (current < targetSchemaVersion) {
12→    const step = migrations.get(current);
13→    if (!step) {
14→      throw new Error(`No migration registered from schema version ${current}`);
15→    }
16→    result = step.migrate(result);
17→    current = step.toVersion;
18→  }
19→
20→  return result;
21→}
