 56→    }
 57→    delete floor.level;
 58→
 59→    if (!floor.rooms) floor.rooms = [];
 60→    for (const room of floor.rooms) {
 61→      if (!room.points) room.points = [];
 62→      if (room.area === undefined) room.area = 0;
 63→    }
 64→  });
 65→
 66→  // Backfill door/window type fields for old saves
 67→  for (const floor of project.floors) {
 68→    if (!floor.doors) floor.doors = [];
 69→    for (const door of floor.doors) {
 70→      if (!door.type) door.type = 'swing';
