324→    if (sheet.projectNameOverride === undefined) sheet.projectNameOverride = '';
325→    sheet.titleBlock = {
326→      projectTitleOverride: sheet.titleBlock?.projectTitleOverride ?? '',
327→      projectAddressOverride: sheet.titleBlock?.projectAddressOverride ?? '',
328→      drawnBy: sheet.titleBlock?.drawnBy ?? '',
329→      checkedBy: sheet.titleBlock?.checkedBy ?? '',
330→    };
331→    if (!Array.isArray(sheet.revisions)) sheet.revisions = [];
332→    sheet.revisions = sheet.revisions.map((revision) => ({
333→      ...createSheetRevision(),
334→      ...revision,
335→      id: revision?.id || `revision_${sheet.id}_${Math.random().toString(36).slice(2, 8)}`,
336→    }));
337→    if (!Array.isArray(sheet.viewports)) sheet.viewports = [];
338→
339→    for (const viewport of sheet.viewports) {
340→      if (!viewport.id) {
341→        viewport.id = `viewport_${sheet.id}_${Math.random().toString(36).slice(2, 8)}`;
342→      }
343→      if (viewport.sourceView === undefined) viewport.sourceView = 'plan';
344→      if (viewport.sourceFloorId === undefined) viewport.sourceFloorId = getDefaultActiveFloorId(project);
345→      if (viewport.sourceRefId === undefined) viewport.sourceRefId = null;
346→      if (viewport.x === undefined) viewport.x = 20;
347→      if (viewport.y === undefined) viewport.y = 20;
348→      if (viewport.width === undefined) viewport.width = 160;
349→      if (viewport.height === undefined) viewport.height = 100;
350→      if (viewport.scale === undefined) viewport.scale = 100;
351→      if (viewport.title === undefined) viewport.title = '';
352→      if (viewport.rotation === undefined) viewport.rotation = 0;
353→      if (viewport.role === undefined) viewport.role = viewport.sourceView === '3d_preview'
354→        ? 'supplemental'
355→        : ((viewport.sourceView === 'plan' || viewport.sourceView === 'roof_plan' || viewport.sourceView === 'roof_drainage' || viewport.sourceView === 'truss_plan')
356→          ? 'primary'
357→          : (viewport.sourceView === 'truss_detail' ? 'detail' : 'secondary'));
358→      if (viewport.captionPosition === undefined) viewport.captionPosition = 'below';
359→      if (viewport.referenceNote === undefined) viewport.referenceNote = '';
360→      if (viewport.lockAutoLayout === undefined) viewport.lockAutoLayout = false;
361→      if (viewport.phaseId === undefined) viewport.phaseId = null;
362→      if (viewport.phaseViewMode === undefined) viewport.phaseViewMode = 'all';
363→    }
364→  }
365→
366→  project.phases = normalizePhases(project.phases || []);
367→
368→  return project;
369→}
