1011→function createInitialState(project) {
1012→  const synced = syncProjectStructures({
1013→    ...project,
1014→    floors: sortFloors(project.floors || []),
1015→  });
1016→  return {
1017→    project: synced,
1018→    isDirty: false,
1019→    lastSavedAt: null,
1020→    savedSnapshot: snapshotProject(synced),
1021→    history: [],
1022→    future: [],
1023→  };
1024→}
1025→
1026→export function ProjectProvider({ children, initialProject }) {
1027→  const [state, dispatch] = useReducer(
1028→    projectReducer,
1029→    initialProject || createProject(),
1030→    createInitialState
1031→  );
1032→  return (
1033→    <ProjectContext.Provider value={{ state, dispatch }}>
1034→      {children}
1035→    </ProjectContext.Provider>
1036→  );
1037→}
1038→
1039→export function useProject() {
1040→  const ctx = useContext(ProjectContext);
1041→  if (!ctx) throw new Error('useProject must be used within ProjectProvider');
1042→  const { state, dispatch } = ctx;
1043→
1044→  const duplicateFloor = (floorId) => {
1045→    const floor = state.project.floors.find((entry) => entry.id === floorId) || null;
1046→    return floor ? createDuplicatedFloor(floor) : null;
1047→  };
1048→
1049→  return {
1050→    project: state.project,
1051→    isDirty: state.isDirty,
1052→    lastSavedAt: state.lastSavedAt,
1053→    canUndo: state.history.length > 0,
1054→    canRedo: state.future.length > 0,
1055→    dispatch,
1056→    duplicateFloor,
1057→    getFloor: (floorId) => state.project.floors.find(f => f.id === floorId),
1058→  };
1059→}
